import { normalizeBusinessType } from './businessTypeProfileMap';

export function getMatrixRowForBusinessType(input: string | null | undefined): MatrixRow | null {
  const norm = normalizeBusinessType(input);
  return BUSINESS_TYPE_MATRIX[norm] ?? null;
}

export function getGroupSummary(category: string | null | undefined): GroupSummary | null {
  if (!category) return null;
  return GROUP_PLATFORM_SUMMARY[category] ?? null;
}

/** Top N channels by priority (P first, then S). */
export function topChannels(row: MatrixRow, n = 3): ChannelMeta[] {
  const ranked = CHANNELS.filter(c => row.priorities[c.key] === 'P')
    .concat(CHANNELS.filter(c => row.priorities[c.key] === 'S'));
  return ranked.slice(0, n);
}
